// Bounded channel với backpressure
var channel = Channel.CreateBounded<WorkItem>(new BoundedChannelOptions(1000)
{
    FullMode = BoundedChannelFullMode.Wait,  // producer chờ khi channel full
    SingleWriter = false,
    SingleReader = false
});

// Multiple producers (concurrent safe)
async Task ProduceAsync(IEnumerable<WorkItem> items, CancellationToken ct)
{
    foreach (var item in items)
        await channel.Writer.WriteAsync(item, ct); // block khi full — backpressure
    channel.Writer.TryComplete();
}

// Multiple consumers (scale out processing)
async Task StartConsumersAsync(int count, CancellationToken ct)
{
    var consumers = Enumerable.Range(0, count)
        .Select(_ => ConsumeAsync(ct));
    await Task.WhenAll(consumers);
}

async Task ConsumeAsync(CancellationToken ct)
{
    await foreach (var item in channel.Reader.ReadAllAsync(ct))
    {
        try { await ProcessAsync(item, ct); }
        catch (Exception ex) { _logger.LogError(ex, "Failed {ItemId}", item.Id); }
        // tiếp tục — không crash consumer
    }
}

// Pipeline: chain nhiều channels
var ingestionCh = Channel.CreateBounded<RawData>(500);
var parsedCh    = Channel.CreateBounded<ParsedData>(500);
var storedCh    = Channel.CreateBounded<StoredEvent>(500);

// Stage 1: ingest → parse
Task.Run(() => TransformAsync(ingestionCh.Reader, parsedCh.Writer, ParseRaw, ct));
// Stage 2: parse → store
Task.Run(() => TransformAsync(parsedCh.Reader, storedCh.Writer, StoreParsed, ct));
